{"path": "/tmp/sv-03d357e945c944319a96793fe8138544/Components/Catalog/CatalogFilters.razor", "file_text": "<div class="catalog-filters">
    <h5>Filters</h5>

    @if (Categories is not null && Categories.Count > 0)
    {
        <div class="filter-section">
            <h6>Category</h6>
            @foreach (var category in Categories)
            {
                <div class="form-check">
                    <input class="form-check-input"
                           type="checkbox"
                           id="@($"cat-{category}")"
                           checked="@_selectedCategories.Contains(category)"
                           @onchange="@(e => ToggleCategory(category, (bool)e.Value!))" />
                    <label class="form-check-label" for="@($"cat-{category}")">@category</label>
                </div>
            }
        </div>
    }

    <div class="filter-section">
        <h6>Price Range</h6>
        <div class="mb-2">
            <label class="form-label small" for="minPrice">Min Price</label>
            <input type="number" class="form-control form-control-sm" id="minPrice"
                   placeholder="Min" min="0" step="0.01"
                   value="@_minPrice" @onchange="@(e => _minPrice = ParseDecimal(e.Value))" />
        </div>
        <div class="mb-2">
            <label class="form-label small" for="maxPrice">Max Price</label>
            <input type="number" class="form-control form-control-sm" id="maxPrice"
                   placeholder="Max" min="0" step="0.01"
                   value="@_maxPrice" @onchange="@(e => _maxPrice = ParseDecimal(e.Value))" />
        </div>
    </div>

    <div class="filter-section">
        <div class="form-check">
            <input class="form-check-input" type="checkbox" id="inStockOnly"
                   checked="@_inStockOnly"
                   @onchange="@(e => _inStockOnly = (bool)e.Value!)" />
            <label class="form-check-label" for="inStockOnly">In Stock Only</label>
        </div>
    </div>

    <div class="filter-actions">
        <button class="btn btn-primary btn-sm w-100 mb-2" @onclick="ApplyFilters">Apply Filters</button>
        <button class="btn btn-outline-secondary btn-sm w-100" @onclick="ClearFilters">Clear Filters</button>
    </div>
</div>

@code {
    [Parameter]
    public List<string>? Categories { get; set; }

    [Parameter]
    public EventCallback<ProductFilter> OnApplyFilters { get; set; }

    [Parameter]
    public EventCallback OnClearFilters { get; set; }

    private HashSet<string> _selectedCategories = new();
    private decimal? _minPrice;
    private decimal? _maxPrice;
    private bool _inStockOnly;

    private void ToggleCategory(string category, bool isChecked)
    {
        if (isChecked)
            _selectedCategories.Add(category);
        else
            _selectedCategories.Remove(category);
    }

    private async Task ApplyFilters()
    {
        var filter = new ProductFilter(
            Categories: _selectedCategories.Count > 0 ? _selectedCategories.ToList() : null,
            MinPrice: _minPrice,
            MaxPrice: _maxPrice,
            InStockOnly: _inStockOnly
        );
        await OnApplyFilters.InvokeAsync(filter);
    }

    private async Task ClearFilters()
    {
        _selectedCategories.Clear();
        _minPrice = null;
        _maxPrice = null;
        _inStockOnly = false;
        await OnClearFilters.InvokeAsync();
    }

    private static decimal? ParseDecimal(object? value)
    {
        if (value is null || string.IsNullOrWhiteSpace(value.ToString()))
            return null;
        return decimal.TryParse(value.ToString(), out var result) ? result : null;
    }
}
"}

