@page "/catalog"
@using sv_03d357e945c944319a96793fe8138544.Models
@using sv_03d357e945c944319a96793fe8138544.Components.Catalog
@inject IProductService ProductService
@rendermode InteractiveServer

<PageTitle>Product Catalog</PageTitle>

<h3 class="mb-3">Product Catalog</h3>

@if (_error is not null)
{
    <div class="alert alert-danger" role="alert">
        <strong>Error:</strong> @_error
        <button class="btn btn-link" @onclick="RetryLoad">Try again</button>
    </div>
}
else
{
    <div class="catalog-layout">
        <aside class="catalog-sidebar">
            <CatalogFilters Categories="_categories"
                            OnApplyFilters="HandleApplyFilters"
                            OnClearFilters="HandleClearFilters" />
        </aside>

        <main class="catalog-main">
            @if (_loading)
            {
                <div class="d-flex justify-content-center align-items-center py-5">
                    <div class="spinner-border text-primary" role="status">
                        <span class="visually-hidden">Loading products...</span>
                    </div>
                    <span class="ms-2">Loading products...</span>
                </div>
            }
            else if (_result is null || _result.Items.Count == 0)
            {
                <div class="text-center py-5 text-muted">
                    <h5>No products found</h5>
                    <p>Try adjusting your filters or clearing them.</p>
                </div>
            }
            else
            {
                <CatalogToolbar SortBy="@_sortBy"
                                FirstItem="@((_result.Page - 1) * _result.PageSize + 1)"
                                LastItem="@(Math.Min(_result.Page * _result.PageSize, _result.TotalCount))"
                                TotalCount="@_result.TotalCount"
                                OnSortChanged="HandleSortChanged" />

                <div class="product-grid mt-3">
                    @foreach (var product in _result.Items)
                    {
                        <ProductCard Product="product"
                                     OnSelected="HandleProductSelected"
                                     OnAddToCart="HandleAddToCart" />
                    }
                </div>

                @if (TotalPages > 1)
                {
                    <div class="mt-4">
                        <CatalogPagination CurrentPage="@_page"
                                           TotalPages="@TotalPages"
                                           OnPageChanged="HandlePageChanged" />
                    </div>
                }
            }
        </main>
    </div>
}

@code {
    private const int PageSize = 12;

    [Parameter]
    public EventCallback<int> OnProductSelected { get; set; }

    private List<string>? _categories;
    private PagedResult<Product>? _result;
    private ProductFilter _filter = new(null, null, null, false);
    private string _sortBy = "price_asc";
    private int _page = 1;
    private bool _loading = true;
    private string? _error;

    private int TotalPages => _result is null || _result.PageSize == 0
        ? 1
        : (int)Math.Ceiling((double)_result.TotalCount / _result.PageSize);

    protected override async Task OnInitializedAsync()
    {
        await LoadDataAsync();
    }

    private async Task LoadDataAsync()
    {
        try
        {
            _loading = true;
            _error = null;

            var categoriesTask = _categories is null
                ? ProductService.GetCategoriesAsync()
                : Task.FromResult(_categories);
            var productsTask = ProductService.SearchAsync(_filter, _sortBy, _page, PageSize);

            await Task.WhenAll(categoriesTask, productsTask);

            _categories = await categoriesTask;
            _result = await productsTask;
        }
        catch (Exception ex)
        {
            _error = ex.Message;
        }
        finally
        {
            _loading = false;
        }
    }

    private async Task HandleApplyFilters(ProductFilter filter)
    {
        _filter = filter;
        _page = 1;
        await LoadDataAsync();
    }

    private async Task HandleClearFilters()
    {
        _filter = new ProductFilter(null, null, null, false);
        _page = 1;
        await LoadDataAsync();
    }

    private async Task HandleSortChanged(string sortBy)
    {
        _sortBy = sortBy;
        _page = 1;
        await LoadDataAsync();
    }

    private async Task HandlePageChanged(int page)
    {
        _page = page;
        await LoadDataAsync();
    }

    private async Task HandleProductSelected(int productId)
    {
        await OnProductSelected.InvokeAsync(productId);
    }

    private Task HandleAddToCart(Product product)
    {
        // Placeholder for cart integration
        return Task.CompletedTask;
    }

    private async Task RetryLoad()
    {
        await LoadDataAsync();
    }
}

.catalog-layout {
    display: flex;
    gap: 1.5rem;
}

.catalog-sidebar {
    flex: 0 0 25%;
    max-width: 25%;
}

.catalog-main {
    flex: 1;
    min-width: 0;
}

.product-grid {
    display: grid;
    grid-template-columns: repeat(auto-fill, minmax(220px, 1fr));
    gap: 1.25rem;
}

::deep .filter-section {
    margin-bottom: 1rem;
    padding-bottom: 1rem;
    border-bottom: 1px solid #e9ecef;
}

::deep .filter-section:last-of-type {
    border-bottom: none;
}

::deep .catalog-filters {
    background: #f8f9fa;
    border: 1px solid #dee2e6;
    border-radius: 8px;
    padding: 1rem;
    position: sticky;
    top: 1rem;
}

@media (max-width: 768px) {
    .catalog-layout {
        flex-direction: column;
    }

    .catalog-sidebar {
        flex: none;
        max-width: 100%;
    }

    .product-grid {
        grid-template-columns: repeat(auto-fill, minmax(160px, 1fr));
    }
}

